import { z } from 'zod';

export const projectNameSchema = z
  .string()
  .min(1)
  .max(59)
  .regex(/^[a-z][a-z0-9_]*$/, 'Must start with lowercase letter, only a-z0-9_ allowed');

export function toSchemaName(name: string): string {
  return `co_${name}`;
}

export const projectStatusSchema = z.enum(['provisioning', 'active', 'deleting', 'error']);

export const projectSchema = z.object({
  id: z.string().uuid(),
  name: z.string(),
  schema_name: z.string(),
  anon_key: z.string().nullable(),
  service_key: z.string().nullable(),
  status: projectStatusSchema,
  created_at: z.string().datetime(),
});

export const createProjectOptionsSchema = z.object({
  name: projectNameSchema,
});

export const dropSchemaOptionsSchema = z.object({
  confirm: z.string(),
});

export type Project = z.infer<typeof projectSchema>;
export type ProjectStatus = z.infer<typeof projectStatusSchema>;
export type CreateProjectOptions = z.infer<typeof createProjectOptionsSchema>;
export type DropSchemaOptions = z.infer<typeof dropSchemaOptionsSchema>;
