import type { PoolClient } from 'pg';
import type { CreateProjectOptions, Project, ProjectStatus } from './types.js';
import { projectSchema, toSchemaName } from './types.js';

export async function insertRegistryRow(
  client: PoolClient,
  options: CreateProjectOptions,
  status: ProjectStatus
): Promise<Project> {
  const schemaName = toSchemaName(options.name);
  const result = await client.query(
    `INSERT INTO _admin.projects (name, schema_name, status)
     VALUES ($1, $2, $3)
     RETURNING id, name, schema_name, anon_key, service_key, status, to_char(created_at AT TIME ZONE 'UTC', 'YYYY-MM-DD"T"HH24:MI:SS.MS"Z"') AS created_at`,
    [options.name, schemaName, status]
  );
  return projectSchema.parse(result.rows[0]);
}

export async function updateRegistryStatus(
  client: PoolClient,
  id: string,
  status: ProjectStatus
): Promise<void> {
  await client.query('UPDATE _admin.projects SET status = $1 WHERE id = $2', [
    status,
    id,
  ]);
}

export async function deleteRegistryRow(
  client: PoolClient,
  id: string
): Promise<void> {
  await client.query('DELETE FROM _admin.projects WHERE id = $1', [id]);
}

export async function findProjectByName(
  client: PoolClient,
  name: string
): Promise<Project | null> {
  const result = await client.query(
    `SELECT id, name, schema_name, anon_key, service_key, status, to_char(created_at AT TIME ZONE 'UTC', 'YYYY-MM-DD"T"HH24:MI:SS.MS"Z"') AS created_at
     FROM _admin.projects WHERE name = $1`,
    [name]
  );
  if (result.rows.length === 0) return null;
  return projectSchema.parse(result.rows[0]);
}

export async function updateRegistryKeys(
  client: PoolClient,
  id: string,
  anonKey: string,
  serviceKey: string
): Promise<void> {
  await client.query(
    'UPDATE _admin.projects SET anon_key = $1, service_key = $2 WHERE id = $3',
    [anonKey, serviceKey, id]
  );
}

/**
 * Sync PostgREST's db-schemas config with current active project schemas.
 * Uses in-database configuration (ALTER ROLE authenticator SET pgrst.db_schemas)
 * and NOTIFY to reload PostgREST without container restart.
 */
export async function syncPostgrestSchemas(client: PoolClient): Promise<void> {
  const baseSchemas = 'public,storage,graphql_public';

  const result = await client.query(
    `SELECT schema_name FROM _admin.projects WHERE status = 'active' ORDER BY created_at ASC`
  );

  const projectSchemas = result.rows.map(
    (row: { schema_name: string }) => row.schema_name
  );
  const allSchemas =
    projectSchemas.length > 0
      ? `${baseSchemas},${projectSchemas.join(',')}`
      : baseSchemas;

  await client.query(
    `ALTER ROLE authenticator SET pgrst.db_schemas = '${allSchemas}'`
  );
  await client.query(`NOTIFY pgrst, 'reload config'`);
}
