import { SignJWT } from 'jose';
import { SetupError } from './errors.js';

export interface KeyManager {
  signAnonKey(projectName: string): Promise<string>;
  signServiceKey(projectName: string): Promise<string>;
}

export function createKeyManager(jwtSecret: string): KeyManager {
  if (!jwtSecret) {
    throw new SetupError('JWT_SECRET is required but was not provided');
  }

  const secretBytes = new TextEncoder().encode(jwtSecret);

  async function signToken(role: string): Promise<string> {
    const iat = Math.floor(Date.now() / 1000);
    const exp = iat + 5 * 365 * 24 * 3600;
    return new SignJWT({ role, iss: 'supabase', iat, exp })
      .setProtectedHeader({ alg: 'HS256' })
      .sign(secretBytes);
  }

  return {
    signAnonKey(projectName: string): Promise<string> {
      return signToken(`co_${projectName}_anon`);
    },
    signServiceKey(projectName: string): Promise<string> {
      return signToken(`co_${projectName}_service`);
    },
  };
}
